/**
 * Verify that every public composable and utility has a co-located `.d.ts`
 * declaration file. Exits with a non-zero code and lists any missing files if
 * the check fails.
 *
 * Composables: every subdirectory of `src/composables/` that contains a
 * primary `.js` file matching the directory name.
 *
 * Utilities: every source file referenced by `src/utilities/index.js` exports.
 *
 * Barrel declaration files (`composables.d.ts`, `utilities.d.ts`) are
 * auto-generated by `publish-declarations.js` during build and are not checked
 * here.
 */

import { existsSync, readFileSync, readdirSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { join } from "node:path";
import process from "node:process";

const root = fileURLToPath(new URL("..", import.meta.url));
const composablesDir = join(root, "src/composables");
const utilitiesDir = join(root, "src/utilities");

const missing = [];

let checked = 0;

// Composables — every subdirectory must have a co-located `.d.ts`.
for (const entry of readdirSync(composablesDir, { withFileTypes: true })) {
	if (!entry.isDirectory()) {
		continue;
	}

	const name = entry.name;
	const jsFile = join(composablesDir, name, `${name}.js`);
	const dtsFile = join(composablesDir, name, `${name}.d.ts`);

	if (!existsSync(jsFile)) {
		continue;
	}

	checked++;

	if (!existsSync(dtsFile)) {
		missing.push(`src/composables/${name}/${name}.d.ts`);
	}
}

// Utilities — check each path referenced by `src/utilities/index.js` exports.
const indexSource = readFileSync(join(utilitiesDir, "index.js"), "utf8");
const exportedPaths = [...indexSource.matchAll(/from\s+"([^"]+)"/g)].map(([, path]) => path);

for (const importPath of exportedPaths) {
	const dtsPath = importPath.replace(/\.js$/, ".d.ts");
	const absPath = join(utilitiesDir, dtsPath);

	checked++;

	if (!existsSync(absPath)) {
		missing.push(`src/utilities/${dtsPath}`);
	}
}

if (missing.length > 0) {
	console.error("Missing declaration files:");

	for (const file of missing) {
		console.error(`  ${file}`);
	}

	process.exit(1);
}

console.log(`Declaration check passed (${checked} checked).`);
